// ══════════════════════════════════════════════════════════════
// STANDALONE FORM FIELD - uncontrolled to prevent mobile keyboard dismiss
// ══════════════════════════════════════════════════════════════
function FormField({ label, k, type, placeholder, options, required, maxLen, form, onSet, errors }) {
  const ref = React.useRef(null);

  // Sync ref value only on mount and when form resets (not on every keystroke)
  React.useEffect(() => {
    if (ref.current && ref.current.value !== form[k]) {
      ref.current.value = form[k];
    }
  }, []); // only on mount

  const handleBlur = (e) => {
    onSet(k, e.target.value);
  };

  const handleChange = (e) => {
    if (maxLen && e.target.value.length > maxLen) {
      e.target.value = e.target.value.slice(0, maxLen);
    }
    // Update parent state on every change (but since input is uncontrolled, no re-render)
    onSet(k, e.target.value);
  };

  return (
    <div style={{ marginBottom: 18 }}>
      <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>
        {label} {required && <span style={{ color: "#EF4444" }}>*</span>}
      </label>
      {options ? (
        <select defaultValue={form[k]} onChange={handleChange} style={inputStyle(errors[k])}>
          <option value="">Select...</option>
          {options.map(o => <option key={o} value={o}>{o}</option>)}
        </select>
      ) : type === "textarea" ? (
        <textarea ref={ref} defaultValue={form[k]} onChange={handleChange} onBlur={handleBlur}
          placeholder={placeholder} rows={4} style={{ ...inputStyle(errors[k]), resize: "vertical" }} />
      ) : (
        <input ref={ref} type={type || "text"} defaultValue={form[k]}
          onChange={handleChange} onBlur={handleBlur}
          placeholder={placeholder} style={inputStyle(errors[k])}
          autoComplete="off" autoCorrect="off" spellCheck="false" />
      )}
      {errors[k] && <div style={{ color: "#EF4444", fontSize: 12, marginTop: 4 }}>{errors[k]}</div>}
    </div>
  );
}

function ApplicationForm({ job, onBack, onSubmit, lang, t }) {
  const tl = t || T.en;
  const isMobile = useIsMobile();
  const cols = isMobile ? "1fr" : "1fr 1fr";

  // All inputs use refs — no controlled state = no re-render = keyboard stays open
  const nameRef = useRef();
  const emailRef = useRef();
  const whatsappRef = useRef();
  const linkedinRef = useRef();
  const cityRef = useRef();
  const experienceRef = useRef();
  const softwareRef = useRef();
  const salaryRef = useRef();
  const motivationRef = useRef();
  const usClientsDetailRef = useRef();

  // Selects need state (no ref alternative)
  const [english, setEnglish] = useState("");
  const [availability, setAvailability] = useState("");
  const [experienceLevel, setExperienceLevel] = useState("");
  const [usClients, setUsClients] = useState("");
  const [resume, setResume] = useState(null);
  const [submitted, setSubmitted] = useState(false);
  const [submittedId, setSubmittedId] = useState("");
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});

  function handleResumeUpload(e) {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) { setErrors(err => ({ ...err, resume: "Max 5MB" })); return; }
    const allowed = ["application/pdf","application/msword","application/vnd.openxmlformats-officedocument.wordprocessingml.document"];
    if (!allowed.includes(file.type)) { setErrors(err => ({ ...err, resume: "PDF or Word only" })); return; }
    const reader = new FileReader();
    reader.onload = () => { setResume({ name: file.name, base64: reader.result, size: file.size }); };
    reader.readAsDataURL(file);
  }

  function getVals() {
    return {
      name: nameRef.current?.value?.trim() || "",
      email: emailRef.current?.value?.trim() || "",
      whatsapp: whatsappRef.current?.value?.trim() || "",
      linkedin: linkedinRef.current?.value?.trim() || "",
      city: cityRef.current?.value?.trim() || "",
      english,
      experience: experienceRef.current?.value?.trim() || "",
      software: softwareRef.current?.value?.trim() || "",
      availability,
      salary: salaryRef.current?.value?.trim() || "",
      motivation: motivationRef.current?.value?.trim() || "",
      experienceLevel,
      usClients,
      usClientsDetail: usClientsDetailRef.current?.value?.trim() || "",
    };
  }

  async function handleSubmit() {
    const vals = getVals();
    const e = {};
    if (!vals.name) e.name = tl.required;
    if (!vals.email || !vals.email.includes("@")) e.email = tl.invalidEmail;
    if (!vals.whatsapp) e.whatsapp = tl.required;
    if (!vals.english) e.english = tl.selectLevel;
    if (!vals.experience) e.experience = tl.required;
    if (!vals.experienceLevel) e.experienceLevel = tl.selectLevel;
    if (!vals.usClients) e.usClients = tl.selectLevel;
    if (Object.keys(e).length) { setErrors(e); return; }

    setLoading(true);
    const existing = await loadCandidates();
    const duplicate = existing.find(c => c.email.toLowerCase() === vals.email.toLowerCase() && c.jobId === job.id);
    if (duplicate) {
      setErrors({ email: tl.duplicateEmail || "You already applied for this position." });
      setLoading(false);
      return;
    }

    const candidate = {
      id: generateId(), jobId: job.id, jobTitle: job.title, company: job.company,
      appliedAt: new Date().toISOString(), status: "new",
      resume: resume ? { name: resume.name, base64: resume.base64, size: resume.size } : null,
      ...vals,
    };
    await saveCandidate(candidate);
    const appId = "AS-" + candidate.id.toUpperCase().slice(0,6);
    setSubmittedId(appId);
    setSubmitted(true);
    setLoading(false);
    onSubmit && onSubmit(candidate);
  }

  const inp = (ref, type, ph, errKey) => (
    <input ref={ref} type={type || "text"} placeholder={ph}
      style={inputStyle(errKey ? errors[errKey] : null)}
      autoComplete="off" spellCheck="false" />
  );

  if (submitted) return (
    <div style={{ textAlign: "center", padding: "48px 24px" }}>
      <div style={{ width: 72, height: 72, borderRadius: "50%", background: "#EEF2FF", border: "2px solid #1B4FD8", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 32, margin: "0 auto 20px" }}>🎉</div>
      <h2 style={{ fontSize: 26, fontWeight: 900, color: "#0A1628", marginBottom: 8 }}>{tl.successTitle}</h2>
      <p style={{ color: "#2E3D5C", fontSize: 14, maxWidth: 400, margin: "0 auto 24px", lineHeight: 1.7 }}>{tl.successMsg(job.title)}</p>
      <div style={{ background: "#F5F7FA", border: "1px solid #E2E6EE", borderRadius: 12, padding: "14px 20px", maxWidth: 320, margin: "0 auto 28px", display: "flex", alignItems: "center", gap: 12 }}>
        <div style={{ fontSize: 20 }}>🔖</div>
        <div style={{ textAlign: "left" }}>
          <div style={{ fontSize: 10, fontWeight: 800, color: "#6B7A99", textTransform: "uppercase", letterSpacing: 1 }}>Application ID</div>
          <div style={{ fontSize: 14, fontWeight: 800, color: "#0A1628", marginTop: 2 }}>{submittedId}</div>
        </div>
      </div>
      <div style={{ background: "#EEF2FF", border: "1px solid #C7D7F5", borderRadius: 14, padding: "20px 24px", maxWidth: 400, margin: "0 auto 28px", textAlign: "left" }}>
        <div style={{ fontSize: 12, fontWeight: 800, color: "#1B4FD8", textTransform: "uppercase", letterSpacing: 1, marginBottom: 14 }}>What happens next</div>
        {[
          { icon: "📋", step: "Application reviewed", time: "Within 3 business days" },
          { icon: "📱", step: "We contact you via WhatsApp or email", time: "If your profile matches" },
          { icon: "🎤", step: "Interview scheduled", time: "With Asoares International Staffing" },
        ].map((s, i) => (
          <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: 10, marginBottom: i < 2 ? 12 : 0 }}>
            <span style={{ fontSize: 16 }}>{s.icon}</span>
            <div>
              <div style={{ fontSize: 13, fontWeight: 700, color: "#0A1628" }}>{s.step}</div>
              <div style={{ fontSize: 11, color: "#6B7A99", marginTop: 1 }}>{s.time}</div>
            </div>
          </div>
        ))}
      </div>
      <button onClick={onBack} style={{ background: "#1B4FD8", color: "#fff", border: "none", borderRadius: 10, padding: "12px 28px", fontSize: 14, fontWeight: 700, cursor: "pointer" }}>{tl.viewJobs}</button>
    </div>
  );

  return (
    <div>
      <button onClick={onBack} style={{ background: "none", border: "none", color: "#1B4FD8", cursor: "pointer", fontSize: 14, fontWeight: 600, marginBottom: 24, padding: 0 }}>{tl.back}</button>
      <div style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 10, fontWeight: 800, letterSpacing: 2, color: "#1B4FD8", textTransform: "uppercase", marginBottom: 4 }}>{job.company}</div>
        <h2 style={{ fontSize: 26, fontWeight: 800, color: "#0A1628", margin: 0 }}>{tl.applyTitle} {job.title}</h2>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: cols, gap: "0 24px" }}>
        {[
          { label: tl.fields.name, ref: nameRef, type: "text", ph: tl.placeholders.name, err: "name", req: true },
          { label: tl.fields.email, ref: emailRef, type: "email", ph: tl.placeholders.email, err: "email", req: true },
          { label: tl.fields.whatsapp, ref: whatsappRef, type: "tel", ph: tl.placeholders.whatsapp, err: "whatsapp", req: true },
          { label: tl.fields.city, ref: cityRef, type: "text", ph: tl.placeholders.city, err: null, req: false },
          { label: tl.fields.software, ref: softwareRef, type: "text", ph: tl.placeholders.software, err: null, req: false },
          { label: tl.fields.salary, ref: salaryRef, type: "text", ph: tl.placeholders.salary, err: null, req: false },
        ].map(({ label, ref, type, ph, err, req }) => (
          <div key={label} style={{ marginBottom: 18 }}>
            <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>
              {label} {req && <span style={{ color: "#EF4444" }}>*</span>}
            </label>
            <input ref={ref} type={type} placeholder={ph} style={inputStyle(err ? errors[err] : null)} autoComplete="off" />
            {err && errors[err] && <div style={{ color: "#EF4444", fontSize: 12, marginTop: 4 }}>{errors[err]}</div>}
          </div>
        ))}

        {/* English level */}
        <div style={{ marginBottom: 18 }}>
          <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>
            {tl.fields.english} <span style={{ color: "#EF4444" }}>*</span>
          </label>
          <select value={english} onChange={e => setEnglish(e.target.value)} style={inputStyle(errors.english)}>
            <option value="">Select...</option>
            {tl.englishLevels.map(o => <option key={o} value={o}>{o}</option>)}
          </select>
          {errors.english && <div style={{ color: "#EF4444", fontSize: 12, marginTop: 4 }}>{errors.english}</div>}
        </div>

        {/* Availability */}
        <div style={{ marginBottom: 18 }}>
          <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>{tl.fields.availability}</label>
          <select value={availability} onChange={e => setAvailability(e.target.value)} style={inputStyle()}>
            <option value="">Select...</option>
            {tl.availOptions.map(o => <option key={o} value={o}>{o}</option>)}
          </select>
        </div>
      </div>

      {/* Experience */}
      <div style={{ marginBottom: 18 }}>
        <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>
          {tl.fields.experience} <span style={{ color: "#EF4444" }}>*</span>
        </label>
        <textarea ref={experienceRef} placeholder={tl.placeholders.experience} rows={4}
          style={{ ...inputStyle(errors.experience), resize: "vertical" }} />
        {errors.experience && <div style={{ color: "#EF4444", fontSize: 12, marginTop: 4 }}>{errors.experience}</div>}
      </div>

      {/* Experience level + US clients */}
      <div style={{ display: "grid", gridTemplateColumns: cols, gap: "0 24px" }}>
        <div style={{ marginBottom: 18 }}>
          <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>
            {tl.fields.experienceLevel} <span style={{ color: "#EF4444" }}>*</span>
          </label>
          <select value={experienceLevel} onChange={e => setExperienceLevel(e.target.value)} style={inputStyle(errors.experienceLevel)}>
            <option value="">Select...</option>
            {tl.experienceLevels.map(o => <option key={o} value={o}>{o}</option>)}
          </select>
          {errors.experienceLevel && <div style={{ color: "#EF4444", fontSize: 12, marginTop: 4 }}>{errors.experienceLevel}</div>}
        </div>
        <div style={{ marginBottom: 18 }}>
          <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>
            {tl.fields.usClients} <span style={{ color: "#EF4444" }}>*</span>
          </label>
          <select value={usClients} onChange={e => setUsClients(e.target.value)} style={inputStyle(errors.usClients)}>
            <option value="">Select...</option>
            <option value="Yes">{tl.yes}</option>
            <option value="No">{tl.no}</option>
          </select>
          {errors.usClients && <div style={{ color: "#EF4444", fontSize: 12, marginTop: 4 }}>{errors.usClients}</div>}
        </div>
      </div>

      {usClients === "Yes" && (
        <div style={{ marginBottom: 18 }}>
          <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>{tl.fields.usClientsDetail}</label>
          <textarea ref={usClientsDetailRef} placeholder={tl.placeholders.usClientsDetail} rows={3}
            style={{ ...inputStyle(), resize: "vertical" }} />
        </div>
      )}

      {/* Motivation */}
      <div style={{ marginBottom: 18 }}>
        <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 6 }}>{tl.fields.motivation}</label>
        <textarea ref={motivationRef} placeholder={tl.placeholders.motivation} rows={4}
          style={{ ...inputStyle(), resize: "vertical" }} />
      </div>

      {/* LinkedIn */}
      <div style={{ background: "#EEF2FF", borderRadius: 12, padding: "14px 18px", marginBottom: 18, display: "flex", alignItems: "center", gap: 12 }}>
        <span style={{ fontSize: 20 }}>💼</span>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: "#1B4FD8", marginBottom: 2 }}>{tl.fields.linkedin}</div>
          <input ref={linkedinRef} placeholder={tl.placeholders.linkedin}
            style={{ ...inputStyle(null), background: "#fff", marginBottom: 0 }} autoComplete="off" />
        </div>
      </div>

      {/* Resume upload */}
      <div style={{ marginBottom: 24 }}>
        <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2E3D5C", marginBottom: 8 }}>
          {tl.fields.resume} <span style={{ color: "#9CA3AF", fontWeight: 400 }}>({tl.fields.resumeHint})</span>
        </label>
        <label style={{ display: "flex", alignItems: "center", gap: 14, cursor: "pointer",
          border: "2px dashed " + (errors.resume ? "#DC2626" : resume ? "#16A34A" : "#C7D7F5"),
          borderRadius: 12, padding: "20px 24px",
          background: resume ? "#F0FDF4" : "#F8FAFF", transition: "all 0.2s"
        }}>
          <input type="file" accept=".pdf,.doc,.docx" onChange={handleResumeUpload} style={{ display: "none" }} />
          <span style={{ fontSize: 28 }}>{resume ? "✅" : "📄"}</span>
          <div>
            {resume ? (
              <>
                <div style={{ fontWeight: 700, color: "#059669", fontSize: 14 }}>{resume.name}</div>
                <div style={{ color: "#6B7280", fontSize: 12, marginTop: 2 }}>
                  {(resume.size / 1024).toFixed(0)} KB ·{" "}
                  <span onClick={e => { e.preventDefault(); setResume(null); }} style={{ color: "#EF4444", cursor: "pointer", textDecoration: "underline" }}>
                    {tl.fields.resumeRemove}
                  </span>
                </div>
              </>
            ) : (
              <>
                <div style={{ fontWeight: 600, color: "#1B4FD8", fontSize: 14 }}>{tl.fields.resumeClick}</div>
                <div style={{ color: "#9CA3AF", fontSize: 12, marginTop: 2 }}>{tl.fields.resumeFormats}</div>
              </>
            )}
          </div>
        </label>
        {errors.resume && <div style={{ color: "#DC2626", fontSize: 12, marginTop: 4 }}>{errors.resume}</div>}
      </div>

      <button onClick={handleSubmit} disabled={loading} style={{
        width: "100%", background: loading ? "#6B7A99" : "#1B4FD8",
        color: "#fff", border: "none", borderRadius: 10, padding: "15px",
        fontSize: 16, fontWeight: 700, cursor: loading ? "not-allowed" : "pointer",
        boxShadow: loading ? "none" : "0 4px 18px rgba(27,79,216,0.3)",
      }}>
        {loading ? tl.sending : tl.send}
      </button>
    </div>
  );
}


function PreScreen({ job, t, lang, onBack }) {
  const isMobile = useIsMobile();
  const [step, setStep] = useState("questions"); // questions | disqualified | form
  const [answers, setAnswers] = useState({});

  const questions = [
    {
      id: "english",
      q: lang === "pt" ? "Qual é o seu nível de inglês?" : lang === "es" ? "¿Cuál es tu nivel de inglés?" : "What is your English level?",
      options: lang === "pt"
        ? ["Básico / Nunca usei profissionalmente", "Intermediário — consigo me virar", "Avançado — trabalho em inglês", "Fluente / Nativo"]
        : lang === "es"
        ? ["Básico / Nunca lo usé profesionalmente", "Intermedio — me las arreglo", "Avanzado — trabajo en inglés", "Fluido / Nativo"]
        : ["Basic / Never used professionally", "Intermediate — I can get by", "Advanced — I work in English", "Fluent / Native"],
      disqualify: [0, 1], // indices that disqualify
    },
    {
      id: "usExperience",
      q: lang === "pt" ? "Você tem experiência trabalhando com clientes ou empresas nos EUA?" : lang === "es" ? "¿Tienes experiencia trabajando con clientes o empresas en EE.UU.?" : "Do you have experience working with U.S. clients or companies?",
      options: lang === "pt"
        ? ["Não, nunca trabalhei com o mercado americano", "Indiretamente — entendo o contexto", "Sim, já trabalhei diretamente com empresas americanas"]
        : lang === "es"
        ? ["No, nunca trabajé con el mercado estadounidense", "Indirectamente — entiendo el contexto", "Sí, ya trabajé directamente con empresas americanas"]
        : ["No, never worked with the U.S. market", "Indirectly — I understand the context", "Yes, I've worked directly with U.S. companies"],
      disqualify: [0],
    },
    {
      id: "availability",
      q: lang === "pt" ? "Você tem disponibilidade de overlap com o horário Mountain Time (EUA)?" : lang === "es" ? "¿Tienes disponibilidad de overlap con el horario Mountain Time (EE.UU.)?" : "Can you overlap with Mountain Time (U.S.) for at least 3–4 hours/day?",
      options: lang === "pt"
        ? ["Não tenho disponibilidade para isso", "Posso me adaptar parcialmente", "Sim, consigo fazer overlap de 3–4h/dia"]
        : lang === "es"
        ? ["No tengo disponibilidad para eso", "Puedo adaptarme parcialmente", "Sí, puedo hacer overlap de 3–4h/día"]
        : ["No, I can't do that", "I can partially adapt", "Yes, I can overlap 3–4 hours/day"],
      disqualify: [0],
    },
  ];

  const [current, setCurrent] = useState(0);

  function handleAnswer(idx) {
    const q = questions[current];
    const newAnswers = { ...answers, [q.id]: idx };
    setAnswers(newAnswers);

    if (q.disqualify.includes(idx)) {
      setStep("disqualified");
      return;
    }
    if (current < questions.length - 1) {
      setCurrent(c => c + 1);
    } else {
      setStep("form");
    }
  }

  if (step === "disqualified") return (
    <div style={{ background: P.white, borderRadius: 20, padding: "48px 32px", border: "1px solid #E2E6EE", textAlign: "center", boxShadow: "0 4px 20px rgba(10,22,40,0.07)" }}>
      <div style={{ fontSize: 48, marginBottom: 16 }}>🙏</div>
      <h3 style={{ fontSize: 22, fontWeight: 900, color: P.navy, marginBottom: 10 }}>
        {lang === "pt" ? "Obrigado pelo interesse!" : lang === "es" ? "¡Gracias por tu interés!" : "Thank you for your interest!"}
      </h3>
      <p style={{ color: P.textMid, fontSize: 14, lineHeight: 1.75, maxWidth: 400, margin: "0 auto 28px" }}>
        {lang === "pt"
          ? "No momento, esta vaga exige um perfil com inglês avançado, experiência com o mercado americano e disponibilidade de horário MT. Continue desenvolvendo essas habilidades — novas oportunidades surgirão!"
          : lang === "es"
          ? "Por el momento, este puesto requiere inglés avanzado, experiencia con el mercado estadounidense y disponibilidad en horario MT. ¡Sigue desarrollando estas habilidades!"
          : "At this moment, this role requires advanced English, U.S. market experience, and Mountain Time availability. Keep developing these skills — new opportunities will come!"}
      </p>
      <button onClick={() => { if (onBack) onBack(); else { setCurrent(0); setAnswers({}); setStep("questions"); } }}
        style={{ background: "none", border: "1.5px solid #E2E6EE", borderRadius: 10, padding: "10px 22px", fontSize: 13, color: P.textMid, fontWeight: 600, cursor: "pointer" }}>
        ← {lang === "pt" ? "Voltar para vagas" : lang === "es" ? "Volver a empleos" : "Back to jobs"}
      </button>
    </div>
  );

  if (step === "form") return (
    <div style={{ background: P.white, borderRadius: 20, padding: isMobile ? "24px 18px" : "36px 40px", border: "1px solid #E2E6EE", boxShadow: "0 4px 20px rgba(10,22,40,0.07)" }}>
      <ApplicationForm job={job} onBack={() => setStep("questions")} onSubmit={() => {}} lang={lang} t={t} />
    </div>
  );

  // Questions step
  const q = questions[current];
  const progress = ((current) / questions.length) * 100;

  return (
    <div style={{ background: P.white, borderRadius: 20, padding: "24px 18px", border: "1px solid #E2E6EE", boxShadow: "0 4px 20px rgba(10,22,40,0.07)" }}>
      {/* Header */}
      <div style={{ marginBottom: 28 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <span style={{ fontSize: 11, fontWeight: 800, color: P.blue, textTransform: "uppercase", letterSpacing: 1 }}>
            {lang === "pt" ? "Verificação rápida" : lang === "es" ? "Verificación rápida" : "Quick check"} · {current + 1}/{questions.length}
          </span>
          <button onClick={onBack} style={{ fontSize: 11, color: P.blue, fontWeight: 700, background: "none", border: "none", cursor: "pointer", padding: 0 }}>{job.company}</button>
        </div>
        {/* Progress bar */}
        <div style={{ height: 3, background: P.surfaceAlt, borderRadius: 99, overflow: "hidden" }}>
          <div style={{ height: "100%", width: (progress + "%"), background: P.blue, borderRadius: 99, transition: "width 0.3s" }} />
        </div>
      </div>

      <h3 style={{ fontSize: 19, fontWeight: 800, color: P.navy, marginBottom: 24, lineHeight: 1.4 }}>{q.q}</h3>

      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {q.options.map((opt, idx) => (
          <button key={idx} onClick={() => handleAnswer(idx)} style={{
            background: P.white, border: "1.5px solid #E2E6EE",
            borderRadius: 12, padding: "14px 18px", textAlign: "left",
            fontSize: 14, color: P.textMid, fontWeight: 500, cursor: "pointer",
            transition: "all 0.15s", display: "flex", alignItems: "center", gap: 12,
          }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = P.blue; e.currentTarget.style.background = P.blueLight; e.currentTarget.style.color = P.navy; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = P.border; e.currentTarget.style.background = P.white; e.currentTarget.style.color = P.textMid; }}
          >
            <div style={{ width: 28, height: 28, borderRadius: "50%", border: "1.5px solid #E2E6EE", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 800, color: P.textMuted, flexShrink: 0 }}>
              {String.fromCharCode(65 + idx)}
            </div>
            {opt}
          </button>
        ))}
      </div>
    </div>
  );
}


